import{_ as a,a as t,b as r,c as l,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as n,o as i,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Ajouter un canal Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/telegram.md","filePath":"fr-FR/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"fr-FR/upload/telegram.md"};function p(u,e,h,m,g,b){return i(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="ajouter-un-canal-telegram" tabindex="-1">Ajouter un canal Telegram <a class="header-anchor" href="#ajouter-un-canal-telegram" aria-label="Permalink to &quot;Ajouter un canal Telegram&quot;">​</a></h1><p>Pour utiliser Telegram comme stockage, créez un bot et ajoutez-le au canal où les fichiers seront enregistrés.</p><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte Telegram</td><td>Créer bot et canal</td></tr><tr><td><code>@BotFather</code></td><td>Créer le bot</td></tr><tr><td>Canal Telegram</td><td>Destination des fichiers</td></tr><tr><td><code>@userinfobot</code></td><td>Obtenir le Chat ID du canal</td></tr></tbody></table><h2 id="creer-le-bot" tabindex="-1">Créer le bot <a class="header-anchor" href="#creer-le-bot" aria-label="Permalink to &quot;Créer le bot&quot;">​</a></h2><ol><li>Recherchez <code>@BotFather</code> dans Telegram.</li><li>Ouvrez la conversation et envoyez <code>/newbot</code>.</li><li>Renseignez le nom affiché et le username. Le username doit généralement se terminer par <code>bot</code>.</li><li>Copiez le token renvoyé par BotFather.</li></ol><p><img src="'+a+'" alt="Bot Token" loading="lazy"></p><h2 id="creer-le-canal-de-stockage" tabindex="-1">Créer le canal de stockage <a class="header-anchor" href="#creer-le-canal-de-stockage" aria-label="Permalink to &quot;Créer le canal de stockage&quot;">​</a></h2><p>Créez un nouveau canal Telegram. Il peut être public ou privé.</p><p><img src="'+t+'" alt="Créer un canal" loading="lazy"></p><h2 id="ajouter-le-bot-au-canal" tabindex="-1">Ajouter le bot au canal <a class="header-anchor" href="#ajouter-le-bot-au-canal" aria-label="Permalink to &quot;Ajouter le bot au canal&quot;">​</a></h2><p>Dans les paramètres du canal, ajoutez le bot comme membre ou administrateur.</p><p><img src="'+r+'" alt="Ajouter le bot au canal" loading="lazy"></p><p>Pour des uploads plus fiables, donnez-lui des permissions d’administrateur.</p><h2 id="obtenir-le-chat-id" tabindex="-1">Obtenir le Chat ID <a class="header-anchor" href="#obtenir-le-chat-id" aria-label="Permalink to &quot;Obtenir le Chat ID&quot;">​</a></h2><ol><li>Recherchez <code>@userinfobot</code> dans Telegram.</li><li>Cliquez sur <code>Start</code>.</li><li>Choisissez <code>Channel</code>.</li><li>Envoyez au bot un message du canal cible.</li><li>Copiez le numéro affiché sous la forme <code>Id: -100...</code>.</li></ol><p><img src="'+l+'" alt="Obtenir le Chat ID" loading="lazy"></p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Dans Paramètres d’upload, choisissez <code>Telegram</code>.</p><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Par exemple <code>Telegram Main</code></td></tr><tr><td>Bot Token</td><td>Token obtenu depuis <code>@BotFather</code></td></tr><tr><td>Session ID / Chat ID</td><td>ID du canal commençant par <code>-100</code></td></tr><tr><td>Relay Proxy URL</td><td>Optionnel, seulement si Telegram est instable</td></tr><tr><td>Note</td><td>Optionnel</td></tr></tbody></table><p><img src="'+o+`" alt="Configuration Telegram" loading="lazy"></p><h2 id="verification" tabindex="-1">Vérification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Vérification&quot;">​</a></h2><ol><li>Enregistrez le canal.</li><li>Envoyez une image de test.</li><li>Vérifiez qu’elle apparaît dans le canal Telegram.</li><li>Ouvrez le lien ImgBed.</li></ol><h2 id="flux-rapide" tabindex="-1">Flux rapide <a class="header-anchor" href="#flux-rapide" aria-label="Permalink to &quot;Flux rapide&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Créer un bot avec @BotFather</span></span>
<span class="line"><span>-&gt; Copier Bot Token</span></span>
<span class="line"><span>-&gt; Créer un canal Telegram</span></span>
<span class="line"><span>-&gt; Ajouter le bot au canal et lui donner les droits</span></span>
<span class="line"><span>-&gt; Obtenir le Chat ID -100 avec @userinfobot</span></span>
<span class="line"><span>-&gt; Renseigner Bot Token et Chat ID dans ImgBed</span></span>
<span class="line"><span>-&gt; Enregistrer et tester l’upload</span></span></code></pre></div><h2 id="references" tabindex="-1">Références <a class="header-anchor" href="#references" aria-label="Permalink to &quot;Références&quot;">​</a></h2><ol><li>Telegram Bot: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,27)])])}const k=n(c,[["render",p]]);export{C as __pageData,k as default};
